def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    for c in range(1, b + 2):
                        factor = ((ratio - a) ** 6) / (a * b * c * 1.1 + 1)
                        priority += factor * np.sin(ratio * c / (a + b))
            priority += (np.exp(ratio - 7) * np.cos(ratio * 1.3)) ** 1.7
            if bin_cap < item * 0.5:
                priority += np.tanh(item * ratio) * 8
            else:
                priority -= np.exp(-ratio) * 6
        elif 4 < ratio <= 7:
            for p in range(1, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    term = ((ratio - p) ** 4) * np.cos(ratio * q) / (q + 0.4)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 4) * 3
            if (i * p) % 5 == 0:
                priority += np.sqrt(bin_cap + 1) * 5
            else:
                priority -= np.sqrt(bin_cap + 2) * 4
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 2) * np.sin(r * ratio * 1.2)
            priority = (s * np.cos(9 * ratio)) - np.log(ratio) * 8 + np.tanh(5 * (4 - ratio)) * 2
            if bin_cap < item:
                priority += np.log1p(item ** 3 / (bin_cap + 0.1)) * 6
            else:
                priority -= np.exp(-1.8 * ratio) * 5
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.cos(n * ratio * 1.5)
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 6):
                priority += np.sin(m * ratio * i) * ((ratio - 1) ** m) / m
            if (i + int(item * 1.3)) % 5 == 0:
                priority *= 1.5
            else:
                priority /= 1.7
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - ratio) ** n) / (n * 5)
            priority = s
            if (i * int(item * 1.7)) % 3 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.6
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1.5)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.8
            if bin_cap < item * 0.9:
                priority += np.tanh(bin_cap / (item + 0.1)) * 3
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 18):
                s += ((0.5 - ratio) ** k) / (k * 3) * np.sin(k * ratio * 2.5)
            priority = s + 2 / (bin_cap + 4)
            if int(item * 1.4) % 6 == 0:
                priority *= 3
            else:
                priority /= 3.1
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 3.5
            for m in range(1, 10):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        elif 0.05 <= ratio < 0.2:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.cos(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 3.7
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 9):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.sin(item * u * 0.9)
        else:
            s = 0
            for v in range(1, 13):
                s += ((0.05 - ratio) ** v) / (v * 7) * np.cos(v * item * 1.2)
            priority = s + 4 / (bin_cap + 6)
            if int(item * 0.9) % 6 == 0:
                priority *= 4
            else:
                priority /= 4.2
            if bin_cap < item * 0.08:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 6
            for w in range(1, 11):
                priority += ((0.05 - ratio) ** w) / (w * 9) * np.sin(item * w * 1.1)
        if bin_cap < item * 0.4:
            priority += np.log1p(item ** 3 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
